PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?romanName ?romanStart ?romanEnd ?hreName ?hreStart ?hreEnd ?romanCapital ?hreCapital
WHERE {
  wd:Q2277 rdfs:label ?romanName ;
           wdt:P580 ?romanStart ;
           wdt:P582 ?romanEnd ;
           wdt:P36 ?romanCapital .
  wd:Q12548 rdfs:label ?hreName ;
            wdt:P580 ?hreStart ;
            wdt:P582 ?hreEnd ;
            wdt:P36 ?hreCapital .
  FILTER (LANG(?romanName) = 'en')
  FILTER (LANG(?hreName) = 'en')

